answer_code:
using System;
using System.Linq;

class Program {
    static void Main() {
        int n = int.Parse(Console.ReadLine());
        int[] arr = Console.ReadLine().Split().Select(int.Parse).ToArray();
        int avg = arr.Sum() / n;
        string g = avg >= 90 ? "A" : avg >= 70 ? "B" : avg >= 50 ? "C" : "D";
        Console.WriteLine(avg);
        Console.WriteLine(g);
    }
}
